18	const PROCESSING_FEE = 5;
19	
20	const BASE_PREMIUMS: Record<string, number> = {
21	  sword: 100,
22	  amulet: 60,
23	  staff: 80,
24	  potion: 40,
25	  rune: 25,
26	};
27	
28	const basePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
29	
30	const sumBasePremiums = (items: Item[]): number => {
31	  const runeCount = items.filter((i) => i.type === "rune").length;
32	  const nonRuneTotal = items
33	    .filter((i) => i.type !== "rune")
34	    .reduce((sum, item) => sum + basePremium(item), 0);
35	  const runeTotal = runeCount === 3 ? 60 : runeCount * 25;
36	  return nonRuneTotal + runeTotal;
37	};
38	
39	const quote = ({ items }: QuoteStep): QuoteResult => ({
40	  premium: sumBasePremiums(items) + PROCESSING_FEE,
41	});
42	
43	export const runScenario = (scenario: Scenario): ScenarioResult => ({
44	  results: scenario.steps.map(quote),
45	});
46

