const RUNE_BLOCK_SIZE = 3;
const RUNE_BLOCK_PRICE = 60;

const basePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;

const runeTotal = (runeCount: number): number =>
  runeCount === RUNE_BLOCK_SIZE
    ? RUNE_BLOCK_PRICE
    : runeCount * BASE_PREMIUMS.rune;

const sumBasePremiums = (items: Item[]): number => {
  const runes = items.filter((i) => i.type === "rune");
  const others = items.filter((i) => i.type !== "rune");
  const othersTotal = others.reduce((sum, item) => sum + basePremium(item), 0);
  return othersTotal + runeTotal(runes.length);
};
